module RefModule(out, clk, rst);output reg [3:0] out;
  input clk, rst;

  wire feedback;

  assign feedback = ~(out[3] ^ out[2]);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge rst or posedge dbg_halt)
  begin
    if (rst)
      out = 4'b0;
    else
      out = {out[2:0],feedback};
  end
endmodule
